function HaLightControl() {
  const [lights, setLights] = React.useState([]);
  const [error, setError] = React.useState('');
  const [busy, setBusy] = React.useState({});
  const refresh = async () => {
    try {
      const r = await titan.api.call('/api/skills/ha_states', { method: 'POST', body: { domain: 'light' } });
      const list = (r?.entities || r || []).filter(e => (e.entity_id||'').startsWith('light.'));
      setLights(list); setError('');
    } catch (e) { setError(String(e?.message||e)); }
  };
  React.useEffect(() => { refresh(); const id = setInterval(refresh, 10000); return () => clearInterval(id); }, []);
  const toggle = async (l) => {
    setBusy(b => ({ ...b, [l.entity_id]: true }));
    try {
      await titan.api.call('/api/skills/ha_call', { method: 'POST', body: { domain: 'light', service: l.state==='on'?'turn_off':'turn_on', entity_id: l.entity_id } });
      await refresh();
    } catch (e) { setError(String(e?.message||e)); }
    finally { setBusy(b => ({ ...b, [l.entity_id]: false })); }
  };
  const setBrightness = async (l, pct) => {
    try { await titan.api.call('/api/skills/ha_call', { method: 'POST', body: { domain: 'light', service: 'turn_on', entity_id: l.entity_id, brightness_pct: pct } }); refresh(); } catch (e) { setError(String(e?.message||e)); }
  };
  return (
    <div style={{padding:14,fontFamily:'system-ui',height:'100%',display:'flex',flexDirection:'column'}}>
      <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:12}}>
        <div style={{fontSize:16,fontWeight:600}}>💡 Lights ({lights.filter(l=>l.state==='on').length}/{lights.length} on)</div>
        <button onClick={refresh} style={{padding:'4px 10px',border:'1px solid #ccc',background:'#fff',borderRadius:4,cursor:'pointer',fontSize:12}}>↻</button>
      </div>
      {error && <div style={{color:'#FF3B30',fontSize:12,marginBottom:6}}>{error.includes('not configured')?'Configure Home Assistant in Settings → Integrations.':error}</div>}
      <div style={{flex:1,overflow:'auto',display:'grid',gridTemplateColumns:'repeat(auto-fill,minmax(200px,1fr))',gap:8}}>
        {lights.map(l => {
          const on = l.state === 'on';
          const brightness = l.attributes?.brightness ? Math.round(l.attributes.brightness/255*100) : 0;
          return (
            <div key={l.entity_id} style={{padding:10,borderRadius:10,background:on?'linear-gradient(135deg,#FFE082,#FFC107)':'#f5f5f5',transition:'background .3s'}}>
              <div style={{display:'flex',alignItems:'center',gap:8,marginBottom:8}}>
                <button onClick={()=>toggle(l)} disabled={busy[l.entity_id]} style={{width:36,height:36,borderRadius:'50%',border:'none',background:on?'#fff':'#ccc',cursor:'pointer',fontSize:18,boxShadow:on?'0 0 12px rgba(255,193,7,0.6)':'none'}}>{on?'💡':'🌑'}</button>
                <div style={{flex:1,fontSize:12,fontWeight:600}}>{l.attributes?.friendly_name || l.entity_id.replace('light.','')}</div>
              </div>
              {on && <input type="range" min="1" max="100" value={brightness} onChange={e=>setBrightness(l, Number(e.target.value))} style={{width:'100%'}}/>}
            </div>
          );
        })}
        {lights.length === 0 && !error && <div style={{gridColumn:'1/-1',textAlign:'center',padding:30,color:'#888'}}>No lights found.</div>}
      </div>
    </div>
  );
}
render(<HaLightControl/>);
